export default async function handler(req, res) {
  // Configuração CORS para permitir chamadas do frontend
  res.setHeader('Access-Control-Allow-Credentials', true);
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.setHeader('Access-Control-Allow-Methods', 'GET,OPTIONS,PATCH,DELETE,POST,PUT');
  res.setHeader(
    'Access-Control-Allow-Headers',
    'X-CSRF-Token, X-Requested-With, Accept, Accept-Version, Content-Length, Content-MD5, Content-Type, Date, X-Api-Version'
  );

  // CRUCIAL: Previne cache no navegador e na edge network para garantir atualizações em tempo real
  res.setHeader('Cache-Control', 'no-store, no-cache, must-revalidate, proxy-revalidate');
  res.setHeader('Pragma', 'no-cache');
  res.setHeader('Expires', '0');

  if (req.method === 'OPTIONS') {
    res.status(200).end();
    return;
  }

  const token = process.env.GITHUB_TOKEN;
  const owner = process.env.GITHUB_OWNER;
  const repo = process.env.GITHUB_REPO;
  const branch = process.env.GITHUB_BRANCH || 'main';
  const path = 'db.json';

  if (!token || !owner || !repo) {
    console.error('Variáveis de ambiente do GitHub não configuradas.');
    return res.status(500).json({ 
      error: 'Configuração de servidor incompleta.',
      details: 'GITHUB_TOKEN, GITHUB_OWNER ou GITHUB_REPO ausentes.' 
    });
  }

  const url = `https://api.github.com/repos/${owner}/${repo}/contents/${path}`;

  // --- LEITURA (GET) ---
  if (req.method === 'GET') {
    try {
      const response = await fetch(`${url}?ref=${branch}`, {
        headers: { 
          Authorization: `Bearer ${token}`,
          Accept: 'application/vnd.github.v3+json',
        },
        cache: 'no-store' // Garante dados frescos do GitHub
      });

      if (response.status === 404) {
        // Arquivo ainda não existe, retorna estrutura vazia padrão
        return res.status(200).json({ history: {}, suppliers: {}, settings: {} });
      }

      if (!response.ok) {
        throw new Error(`GitHub API Error: ${response.status} ${response.statusText}`);
      }

      const data = await response.json();
      const content = Buffer.from(data.content, 'base64').toString('utf-8');

      try {
        const jsonContent = JSON.parse(content);
        return res.status(200).json(jsonContent);
      } catch (parseError) {
        console.error("Erro ao fazer parse do JSON do GitHub:", parseError);
        return res.status(200).json({ history: {}, suppliers: {}, settings: {} });
      }

    } catch (error) {
      console.error("Erro na API (GET):", error);
      return res.status(500).json({ error: 'Falha ao buscar dados na nuvem.' });
    }
  }

  // --- GRAVAÇÃO (POST) ---
  if (req.method === 'POST') {
    try {
      const incomingData = req.body;

      // 1. Buscar dados atuais para pegar o SHA (necessário para update) e fazer o merge
      let currentDB = { history: {}, suppliers: {}, settings: {} };
      let sha = null;

      const getResponse = await fetch(`${url}?ref=${branch}`, {
        headers: { Authorization: `Bearer ${token}` },
        cache: 'no-store'
      });

      if (getResponse.ok) {
        const fileData = await getResponse.json();
        sha = fileData.sha;
        try {
           const content = Buffer.from(fileData.content, 'base64').toString('utf-8');
           currentDB = JSON.parse(content);
        } catch (e) {
           console.warn("Conteúdo existente inválido, sobrescrevendo.");
        }
      } else if (getResponse.status !== 404) {
         // Se for erro diferente de 404, aborta
         throw new Error(`Erro ao ler arquivo existente: ${getResponse.statusText}`);
      }

      // 2. Merge Inteligente: Mantém histórico antigo, adiciona/atualiza o novo
      const mergedDB = {
        history: { ...(currentDB.history || {}), ...(incomingData.history || {}) },
        suppliers: { ...(currentDB.suppliers || {}), ...(incomingData.suppliers || {}) },
        // Configurações: O último a salvar ganha, mas preserva chaves não enviadas
        settings: { ...(currentDB.settings || {}), ...(incomingData.settings || {}) }
      };

      // 3. Preparar Payload
      const contentEncoded = Buffer.from(JSON.stringify(mergedDB, null, 2)).toString('base64');

      const now = new Date();
      const timestamp = now.toLocaleDateString('pt-BR') + ' ' + now.toLocaleTimeString('pt-BR');

      // 4. Enviar para GitHub
      const putResponse = await fetch(url, {
        method: 'PUT',
        headers: {
          Authorization: `Bearer ${token}`,
          Accept: 'application/vnd.github.v3+json',
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          message: `DATA UPDATE: ${timestamp} (Via App)`,
          content: contentEncoded,
          sha: sha, // Se null, cria novo arquivo
          branch: branch
        })
      });

      if (!putResponse.ok) {
        const errData = await putResponse.json();
        throw new Error(errData.message || 'Erro ao salvar no GitHub');
      }

      return res.status(200).json({ success: true, message: 'Dados sincronizados com sucesso.' });

    } catch (error) {
      console.error("Erro na API (POST):", error);
      return res.status(500).json({ error: error.message || 'Falha interna ao salvar.' });
    }
  }

  return res.status(405).json({ error: 'Método não permitido.' });
}

