function App() {
  // 1. INITIAL STATE (Loads directly from local DB for speed)
  const [historicalData, setHistoricalData] = useState<Record<string, FinancialData>>(() => {
    return storageDB.history.load({ 'nov-2025': DATA_NOV });
  });

  const [historicalSuppliers, setHistoricalSuppliers] = useState<Record<string, Supplier[]>>(() => {
    return storageDB.suppliers.load({ 'nov-2025': INITIAL_SUPPLIERS_NOV });
  });

  const [selectedMonthKey, setSelectedMonthKey] = useState<string>(() => {
    const savedKey = storageDB.settings.load().selectedMonthKey;
    const allHistory = storageDB.history.load({ 'nov-2025': DATA_NOV });
    if (savedKey && allHistory[savedKey]) return savedKey;
    const keys = Object.keys(allHistory);
    return keys.length > 0 ? (keys.includes('nov-2025') && keys.length === 1 ? 'nov-2025' : keys[keys.length - 1]) : 'nov-2025';
  });

  const [currentView, setCurrentView] = useState<'dashboard' | 'suppliers'>(() => {
    return storageDB.settings.load().currentView;
  });

  const [isUploading, setIsUploading] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [isConnected, setIsConnected] = useState(false); // New State for Status
  const [lastSaved, setLastSaved] = useState<Date | null>(null);
  const [notification, setNotification] = useState<{message: string, type: 'success' | 'error' | 'info'} | null>(null);

  // Clear notification
  useEffect(() => {
    if (notification) {
      const timer = setTimeout(() => setNotification(null), 5000);
      return () => clearTimeout(timer);
    }
  }, [notification]);

  // SYNC FUNCTION: Loads data from cloud (GitHub) and updates local state
  const loadFromCloud = useCallback(async (isAuto = false) => {
    if (!isAuto) setIsSyncing(true);

    try {
      const cloudData = await cloudDB.load();
      if (cloudData && cloudData.history) {
        setIsConnected(true);
        // Merge cloud data with local data
        const localHistory = storageDB.history.load({ 'nov-2025': DATA_NOV });
        const localSuppliers = storageDB.suppliers.load({ 'nov-2025': INITIAL_SUPPLIERS_NOV });

        const mergedHistory = { ...localHistory, ...cloudData.history };
        const mergedSuppliers = { ...localSuppliers, ...cloudData.suppliers };

        // Save merged data locally
        storageDB.history.save(mergedHistory);
        storageDB.suppliers.save(mergedSuppliers);

        // Update state
        setHistoricalData(mergedHistory);
        setHistoricalSuppliers(mergedSuppliers);

        // Update selection if cloud has newer data/settings and it's an initial load or manual refresh
        const cloudKeys = Object.keys(cloudData.history || {});
        if (cloudKeys.length > 0 && !isAuto) {
           const sortedKeys = cloudKeys.sort((a, b) => {
             const [ma, ya] = a.split('-');
             const [mb, yb] = b.split('-');
             if (ya !== yb) return Number(ya) - Number(yb);
             return MONTH_ORDER.indexOf(ma) - MONTH_ORDER.indexOf(mb);
           });
           const latestKey = sortedKeys[sortedKeys.length - 1];

           // Only change selection if we are viewing default or if explicitly requested
           if (!selectedMonthKey || selectedMonthKey === 'nov-2025') {
               setSelectedMonthKey(latestKey);
           }
        }

        setLastSaved(new Date());
        if (!isAuto) setNotification({ message: "Dados sincronizados com o servidor.", type: 'success' });
      } else {
        // If connected but empty data or null returned
        setIsConnected(false);
      }
    } catch (err) {
      console.error("Erro ao sincronizar:", err);
      setIsConnected(false);
      if (!isAuto) setNotification({ message: "Erro ao conectar com servidor. Verifique credenciais.", type: 'error' });
    } finally {
      setIsSyncing(false);
    }
  }, [selectedMonthKey]);

  // FORCE SAVE TO CLOUD (MANUAL PUSH)
  const handleForceSave = async () => {
    if (isSyncing) return;
    setIsSyncing(true);
    setNotification({ message: "Enviando todos os dados locais para o GitHub...", type: 'info' });

    try {
      const payload = {
        history: historicalData,
        suppliers: historicalSuppliers,
        settings: { selectedMonthKey, currentView }
      };

      await cloudDB.save(payload);
      setNotification({ message: "Sincronização completa! Dados salvos no GitHub.", type: 'success' });
      setLastSaved(new Date());
      setIsConnected(true);
    } catch (err) {
      console.error(err);
      setNotification({ message: "Erro ao enviar para o GitHub. Verifique as credenciais.", type: 'error' });
      setIsConnected(false);
    } finally {
      setIsSyncing(false);
    }
  };

  // INITIAL LOAD - Force load immediately to get persisted data
  useEffect(() => {
    loadFromCloud(false);
  }, []); // Run once on mount

  // REAL-TIME POLLING: Check for updates every 30 seconds
  useEffect(() => {
    const intervalId = setInterval(() => {
      loadFromCloud(true);
    }, 30000); // 30 seconds

    return () => clearInterval(intervalId);
  }, [loadFromCloud]);

  // 2. LOCAL DB AUTO-SAVE EFFECTS
  useEffect(() => {
    storageDB.history.save(historicalData);
  }, [historicalData]);

  useEffect(() => {
    storageDB.suppliers.save(historicalSuppliers);
  }, [historicalSuppliers]);

  useEffect(() => {
    storageDB.settings.save({ selectedMonthKey });
  }, [selectedMonthKey]);

  useEffect(() => {
    storageDB.settings.save({ currentView });
  }, [currentView]);


  // Derived state
  const currentYear = selectedMonthKey.split('-')[1] || new Date().getFullYear().toString();
  const currentMonthPrefix = selectedMonthKey.split('-')[0];

  const allAvailableKeys = useMemo<Set<string>>(() => {
    const keys = new Set<string>();
    Object.keys(historicalData).forEach(k => keys.add(k));
    Object.keys(historicalSuppliers).forEach(k => keys.add(k));
    return keys;
  }, [historicalData, historicalSuppliers]);

  const availableYears = useMemo(() => {
    const years = new Set<string>();
    (Array.from(allAvailableKeys) as string[]).forEach((key: string) => {
      const parts = key.split('-');
      if (parts.length === 2 && !isNaN(Number(parts[1]))) {
        years.add(parts[1]);
      }
    });
    return Array.from(years).sort().reverse();
  }, [allAvailableKeys]);

  const availableMonths = useMemo(() => {
    const BLACKLIST_LABELS = [
      'EST. FISICO VENDA', 'EST. FISICO', 'RAZAO SOCIAL', 'CUSTO', 'VENDA', 
      'COMPRAS', 'BONIFICACAO', 'MKP BRUTO', 'CMV', 'TOTAL', 'TOTAIS'
    ];

    return (Array.from(allAvailableKeys) as string[])
      .filter((key: string) => key.endsWith(`-${currentYear}`))
      .map((key: string) => {
        const prefix = key.split('-')[0];
        const dataLabel = historicalData[key]?.month;
        let label = dataLabel ? dataLabel.replace(currentYear, '').trim() : getLabelFromKey(key).replace(currentYear, '').trim();
        if (!label || label === '') label = prefix.toUpperCase();
        return { id: key, prefix: prefix, label: label };
      })
      .filter(m => !BLACKLIST_LABELS.includes(m.label.toUpperCase()))
      .sort((a, b) => MONTH_ORDER.indexOf(a.prefix) - MONTH_ORDER.indexOf(b.prefix));
  }, [allAvailableKeys, historicalData, currentYear]);

  useEffect(() => {
    if (!allAvailableKeys.has(selectedMonthKey) && allAvailableKeys.size > 0) {
       const keyInYear = (Array.from(allAvailableKeys) as string[]).find((k: string) => k.endsWith(`-${currentYear}`));
       setSelectedMonthKey(keyInYear || (Array.from(allAvailableKeys) as string[])[0]);
    }
  }, [allAvailableKeys, selectedMonthKey, currentYear]);

  const handleYearChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const newYear = e.target.value;
    const targetKey = `${currentMonthPrefix}-${newYear}`;
    if (allAvailableKeys.has(targetKey)) {
      setSelectedMonthKey(targetKey);
    } else {
      const firstAvailableInYear = (Array.from(allAvailableKeys) as string[]).find((k: string) => k.endsWith(`-${newYear}`));
      if (firstAvailableInYear) setSelectedMonthKey(firstAvailableInYear);
    }
  };

  const currentData = useMemo(() => {
    if (historicalData[selectedMonthKey]) return historicalData[selectedMonthKey];
    return { ...EMPTY_DATA, month: getLabelFromKey(selectedMonthKey), lastUpdated: new Date().toLocaleDateString('pt-BR') };
  }, [historicalData, selectedMonthKey]);

  // Calculate Previous Year Data for YoY Comparison
  const previousYearData = useMemo(() => {
    if (!selectedMonthKey) return undefined;
    const [month, year] = selectedMonthKey.split('-');
    if (!month || !year || isNaN(Number(year))) return undefined;

    const prevYear = Number(year) - 1;
    const prevKey = `${month}-${prevYear}`;
    return historicalData[prevKey];
  }, [historicalData, selectedMonthKey]);

  const currentSuppliers = historicalSuppliers[selectedMonthKey] || [];

  const parseSheet = (rows: any[]): any | null => {
    try {
      let totalsRowIndex = -1;
      let headerRowIndex = -1;
      let monthLabel = '';
      let rawMonth = '';
      let rawYear = '';

      const firstCell = rows[0]?.[0]?.toString();
      if (firstCell === 'CONFIG_SISTEMA') return { type: 'backup', config: { selectedKey: rows[1]?.[1], currentView: rows[2]?.[1] }, key: 'config' };

      if (rows.length > 1) {
          const r1 = rows[1];
          if (r1 && r1[2]) {
              const val = r1[2].toString();
              if (val !== 'DIGITE_MES_AQUI' && !val.includes('REF')) rawMonth = val;
              if (r1[3] && r1[3] !== 'DIGITE_ANO_AQUI') rawYear = r1[3].toString();
          }
      }
      for (let i = 0; i < Math.min(rows.length, 5); i++) {
         const row = rows[i] || [];
         if (row.some((cell: any) => typeof cell === 'string' && (cell.includes('REFERÊNCIA') || cell.includes('EXPORTADO')))) {
            const dateCell = row.find((c: any) => typeof c === 'string' && (c.match(/(jan|fev|mar|abr|mai|jun|jul|ago|set|out|nov|dez)/i) || c.match(/\//)));
            if (dateCell) monthLabel = dateCell;
         }
      }
      if (!monthLabel && rawMonth) monthLabel = rawYear ? `${rawMonth} ${rawYear}` : rawMonth;
      if (!monthLabel) {
        for(let i=0; i<Math.min(rows.length, 5); i++) {
            const row = rows[i];
            if (!row) continue;
            const cell = row.find((c: any) => typeof c === 'string' && (c.toLowerCase().match(/^(janeiro|fevereiro|...|dezembro)/i)));
            if (cell) { monthLabel = cell; break; }
        }
      }

      if (!monthLabel) return null;
      const monthId = generateMonthId(monthLabel);
      if (monthId.startsWith('unknown')) return null;

      let generalData: FinancialData | null = null;
      for (let i = 0; i < rows.length; i++) {
        const row = rows[i] as any[];
        if (!row) continue;
        const colB = row[1]?.toString()?.toUpperCase() || '';
        if (colB === 'TOTAIS') { totalsRowIndex = i; break; }
      }
      if (totalsRowIndex !== -1) {
        const valuesRow = rows[totalsRowIndex];

        // CHECK FOR PREVIOUS YEAR MANUAL ROWS (Looking at next 2 rows)
        let manualPrevSales = 0;
        let manualPrevCost = 0;

        // Safety check for array bounds
        if (rows.length > totalsRowIndex + 1) {
           const rowNext = rows[totalsRowIndex + 1];
           // Check if label in Col B (index 1) contains "VENDA ANO ANTERIOR"
           if (rowNext && rowNext[1] && rowNext[1].toString().toUpperCase().includes('VENDA ANO ANTERIOR')) {
               // Assuming value is in Col D (index 3 - aligned with Venda column) or Col C (index 2)
               manualPrevSales = parseCurrencyString(rowNext[3]) || parseCurrencyString(rowNext[2]);
           }
        }

        if (rows.length > totalsRowIndex + 2) {
           const rowNext2 = rows[totalsRowIndex + 2];
           // Check if label in Col B (index 1) contains "CUSTO ANO ANTERIOR"
           if (rowNext2 && rowNext2[1] && rowNext2[1].toString().toUpperCase().includes('CUSTO ANO ANTERIOR')) {
               // Assuming value is in Col E (index 4 - aligned with Custo column) or Col C (index 2)
               manualPrevCost = parseCurrencyString(rowNext2[4]) || parseCurrencyString(rowNext2[2]);
           }
        }

        generalData = {
          lastUpdated: new Date().toLocaleDateString('pt-BR'),
          month: monthLabel.toUpperCase(), 
          inventoryValue: parseCurrencyString(valuesRow[2]), 
          sales: parseCurrencyString(valuesRow[3]),
          cost: parseCurrencyString(valuesRow[4]),
          markup: parseCurrencyString(valuesRow[5])/ (parseCurrencyString(valuesRow[5]) > 10 ? 100 : 1),
          cmv: parseCurrencyString(valuesRow[6])/ (parseCurrencyString(valuesRow[6]) > 10 ? 100 : 1),
          purchases: parseCurrencyString(valuesRow[7]),
          bonuses: parseCurrencyString(valuesRow[8]),
          balancePurchases: parseCurrencyString(valuesRow[10]),
          balanceBonuses: parseCurrencyString(valuesRow[11] || 0),
          manualPreviousSales: manualPrevSales,
          manualPreviousCost: manualPrevCost
        };
      }

      let suppliersData: Supplier[] | null = null;
      for (let i = 0; i < rows.length; i++) {
        const row = rows[i] as string[];
        if (row && row.some(cell => typeof cell === 'string' && cell.toLowerCase().includes('raz'))) { headerRowIndex = i; break; }
      }
      if (headerRowIndex !== -1) {
        const parsedSuppliers: Supplier[] = [];
        for (let i = headerRowIndex + 1; i < rows.length; i++) {
          const row = rows[i] as any[];
          if (!row || row.length < 5) continue;
          const code = row[0]?.toString();
          const name = row[1]?.toString();
          if (code && name && name.length > 2 && code.toLowerCase() !== 'total') {
             parsedSuppliers.push({
                 code: code, name: name,
                 inventory: parseCurrencyString(row[2]),
                 sales: parseCurrencyString(row[3]),
                 cost: parseCurrencyString(row[4]),
                 markup: parseCurrencyString(row[5]) / (parseCurrencyString(row[5]) > 5 ? 100 : 1),
                 cmv: parseCurrencyString(row[6]) / (parseCurrencyString(row[6]) > 5 ? 100 : 1),
                 purchases: parseCurrencyString(row[7]),
                 bonuses: parseCurrencyString(row[8]),
                 balanceDays: parseCurrencyString(row[9]),
                 balancePurchases: parseCurrencyString(row[10]),
                 balanceBonuses: parseCurrencyString(row[11]),
                 mga: parseCurrencyString(row[12]),
                 total: parseCurrencyString(row[13]),
                 compImport: parseCurrencyString(row[14])
             });
          }
        }
        suppliersData = parsedSuppliers;
      }

      if (generalData || suppliersData) return { type: 'general', key: monthId, data: { general: generalData, suppliers: suppliersData, label: monthLabel } };
      return null;
    } catch (error) { return null; }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsUploading(true);
    // Explicit feedback about "saving to script/cloud"
    setNotification({ message: "Processando arquivo e preparando envio...", type: 'info' });

    const reader = new FileReader();
    reader.onload = async (event) => {
      const bstr = event.target?.result;
      const wb = XLSX.read(bstr, { type: 'binary' });

      let isBackup = false;
      const backupData: any = {};
      const monthlyUpdates: any[] = [];

      wb.SheetNames.forEach(sheetName => {
         const ws = wb.Sheets[sheetName];
         const jsonData = XLSX.utils.sheet_to_json(ws, { header: 1 });
         const result = parseSheet(jsonData);
         if (result) {
             if (result.type === 'backup') {
                 isBackup = true;
                 if (result.key === 'general') backupData.general = result.data;
                 if (result.key === 'supplier') backupData.suppliers = result.data;
                 if (result.key === 'config') backupData.config = result.data;
             } else if (result.type === 'general' && result.key) {
                 monthlyUpdates.push({ id: result.key, label: result.data.label, general: result.data.general, suppliers: result.data.suppliers });
             }
         }
      });

      // 1. RELOAD FROM LOCAL DB
      const currentStoredData = storageDB.history.load({ 'nov-2025': DATA_NOV });
      const currentStoredSuppliers = storageDB.suppliers.load({ 'nov-2025': INITIAL_SUPPLIERS_NOV });

      // 2. MERGE LOCAL
      let finalHistory = { ...currentStoredData };
      let finalSuppliers = { ...currentStoredSuppliers };

      // Prepared data specifically for cloud update (optimization)
      const cloudPayload: any = { history: {}, suppliers: {}, settings: { currentView } };

      if (isBackup) {
          finalHistory = { ...finalHistory, ...(backupData.general || {}) };
          finalSuppliers = { ...finalSuppliers, ...(backupData.suppliers || {}) };
          cloudPayload.history = backupData.general;
          cloudPayload.suppliers = backupData.suppliers;
      } else if (monthlyUpdates.length > 0) {
          monthlyUpdates.forEach(update => {
              if (update.general) {
                  finalHistory[update.id] = update.general;
                  cloudPayload.history[update.id] = update.general;
              }
              if (update.suppliers) {
                  finalSuppliers[update.id] = update.suppliers;
                  cloudPayload.suppliers[update.id] = update.suppliers;
              }
          });
      }

      // 3. ATOMIC WRITE TO LOCAL DB
      storageDB.history.save(finalHistory);
      storageDB.suppliers.save(finalSuppliers);

      // 4. UPDATE STATE (UI) - Immediate local feedback
      setHistoricalData(finalHistory);
      setHistoricalSuppliers(finalSuppliers);

      let newSelectedKey = selectedMonthKey;
      if (!isBackup && monthlyUpdates.length > 0) {
        newSelectedKey = monthlyUpdates[monthlyUpdates.length - 1].id;
        setSelectedMonthKey(newSelectedKey);
        cloudPayload.settings.selectedMonthKey = newSelectedKey;
      } else if (isBackup && backupData.config) {
          if (backupData.config.selectedKey) {
             newSelectedKey = backupData.config.selectedKey;
             setSelectedMonthKey(newSelectedKey);
             cloudPayload.settings.selectedMonthKey = newSelectedKey;
          }
          if (backupData.config.currentView) setCurrentView(backupData.config.currentView);
      }

      // 5. SAVE TO CLOUD (GitHub) - Wait for this to complete to ensure persistence
      try {
        setNotification({ message: "Persistindo dados na nuvem (GitHub)... não feche.", type: 'info' });
        // Envia apenas o delta (o que mudou) para ser mergeado pelo servidor
        await cloudDB.save(cloudPayload);
        setNotification({ message: "Sucesso! Dados salvos e persistidos na nuvem.", type: 'success' });
        setLastSaved(new Date());
        setIsConnected(true);
      } catch (err) {
        console.error(err);
        setNotification({ message: "Erro ao persistir na nuvem. Verifique a conexão.", type: 'error' });
        setIsConnected(false);
      }

      setIsUploading(false);
      e.target.value = '';
    };
    reader.readAsBinaryString(file);
