// Helper to generate consistent IDs from month labels
const generateMonthId = (label: string): string => {
  if (!label) return 'unknown';
  const clean = label.toLowerCase().trim();
  const parts = clean.split(/[\/\s-]+/); 

  const monthMap: Record<string, string> = {
    'janeiro': 'jan', 'jan': 'jan',
    'fevereiro': 'fev', 'fev': 'fev',
    'março': 'mar', 'marco': 'mar', 'mar': 'mar',
    'abril': 'abr', 'abr': 'abr',
    'maio': 'mai', 'mai': 'mai',
    'junho': 'jun', 'jun': 'jun',
    'julho': 'jul', 'jul': 'jul',
    'agosto': 'ago', 'ago': 'ago',
    'setembro': 'set', 'set': 'set',
    'outubro': 'out', 'out': 'out',
    'novembro': 'nov', 'nov': 'nov',
    'dezembro': 'dez', 'dez': 'dez'
  };

  let foundMonth = 'geral';
  let foundYear = new Date().getFullYear().toString();

  for (const part of parts) {
    if (monthMap[part]) foundMonth = monthMap[part];
    if (part.length === 4 && !isNaN(Number(part))) foundYear = part;
  }

  return `${foundMonth}-${foundYear}`;
};

