              <div className="relative">
                 <CalendarDays className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none" />
                 <select value={selectedMonthKey} onChange={(e) => setSelectedMonthKey(e.target.value)} className="appearance-none bg-slate-800 text-white pl-9 pr-8 py-2 rounded-lg border border-slate-700 hover:border-slate-600 focus:border-blue-500 outline-none cursor-pointer text-sm font-medium w-32 sm:w-auto">
                   {availableMonths.map(month => <option key={month.id} value={month.id}>{month.label}</option>)}
