              <button onClick={handleDownloadTemplate} className="hidden md:flex items-center justify-center gap-2 bg-slate-800 hover:bg-slate-700 text-slate-300 hover:text-white px-4 py-2 rounded-lg border border-slate-700 transition-all text-sm font-medium" title="Baixar Modelo Importação">
                <FileDown className="w-4 h-4" /><span>Modelo</span>
              </button>
              <label className="cursor-pointer group flex items-center justify-center w-10 h-10 md:w-auto md:h-auto md:gap-2 bg-slate-800 hover:bg-slate-700 md:px-4 md:py-2 rounded-lg border border-slate-700 transition-all shadow-lg hover:shadow-blue-500/20" title="Importar Excel e Atualizar Globalmente">
                {isUploading ? <CloudCog className="w-4 h-4 text-orange-400 animate-spin" /> : <Upload className="w-4 h-4 text-blue-400 group-hover:text-blue-300" />}
                <span className="hidden md:inline text-sm font-medium">Importar</span>
                <input type="file" accept=".xlsx, .xls" className="hidden" onChange={handleFileUpload} disabled={isUploading} />
