        <div className="animate-in fade-in zoom-in duration-300 flex-1">
             {currentView === 'dashboard' ? <Dashboard data={currentData} previousData={previousYearData} /> : <SupplierTable suppliers={currentSuppliers} currentMonth={currentData.month} />}
        </div>

        <div className="mt-8 flex flex-col md:flex-row justify-between items-center text-xs text-slate-500 border-t border-slate-800 pt-4 gap-4">
