import { ClientRecord } from '../types';

export interface SupabaseConfig {
  url: string;
  key: string;
}

export const supabaseService = {
  // Busca todos os clientes do Supabase
  fetchClients: async (config: SupabaseConfig): Promise<ClientRecord[]> => {
    if (!config.url || !config.key) return [];

    const url = `${config.url}/rest/v1/clients?select=*`;

    try {
      const response = await fetch(url, {
        method: 'GET',
        headers: {
          'apikey': config.key,
          'Authorization': `Bearer ${config.key}`,
          'Content-Type': 'application/json'
        }
      });

      if (!response.ok) {
        throw new Error('Falha ao buscar dados do Supabase');
      }

      return await response.json();
    } catch (error) {
      console.error('Erro Supabase Fetch:', error);
      throw error;
    }
  },

  // Salva (Upsert) múltiplos clientes no Supabase
  saveClients: async (config: SupabaseConfig, clients: ClientRecord[]): Promise<void> => {
    if (!config.url || !config.key) return;

    const url = `${config.url}/rest/v1/clients`;

    try {
      // Upsert: insere novos ou atualiza existentes baseados na Primary Key 'id'
      const response = await fetch(url, {
        method: 'POST',
        headers: {
          'apikey': config.key,
          'Authorization': `Bearer ${config.key}`,
          'Content-Type': 'application/json',
          'Prefer': 'resolution=merge-duplicates'
        },
        body: JSON.stringify(clients)
      });

      if (!response.ok) {
        const err = await response.json();
        throw new Error(err.message || 'Erro ao salvar no Supabase');
      }
    } catch (error) {
      console.error('Erro Supabase Save:', error);
      throw error;
    }
  }
};

import React, { useState, useRef, useEffect } from 'react';
import RepresentativeTab from './components/RepresentativeTab';
import CityTab from './components/CityTab';
import SupervisorTab from './components/SupervisorTab';
import ClientListModal from './components/ClientListModal';
import { MOCK_DATA } from './services/mockData';
import { dbService } from './services/database'; 
import { supabaseService, SupabaseConfig } from './services/supabaseService';
import { ClientRecord, ClientStatus } from './types';

type Tab = 'representative' | 'city' | 'supervisor';
type DataSource = 'MOCK' | 'LOCAL_DB' | 'SUPABASE';

const TAB_STORAGE_KEY = 'MILLENIUM_PREF_ACTIVE_TAB';
const SUPABASE_CONFIG_KEY = 'MILLENIUM_SUPABASE_CONFIG';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<Tab>(() => {
    return (localStorage.getItem(TAB_STORAGE_KEY) as Tab) || 'representative';
  });

  const [isLoading, setIsLoading] = useState(true);
  const [loadingMsg, setLoadingMsg] = useState('Processando...');
  const [clientData, setClientData] = useState<ClientRecord[]>([]);
  const [dataSource, setDataSource] = useState<DataSource>('MOCK');

  // Supabase Config State
  const [showConfigModal, setShowConfigModal] = useState(false);
  const [sbConfig, setSbConfig] = useState<SupabaseConfig>(() => {
    const saved = localStorage.getItem(SUPABASE_CONFIG_KEY);
    return saved ? JSON.parse(saved) : { url: '', key: '' };
  });

  // Load Data on Startup
  useEffect(() => {
    const loadData = async () => {
      setIsLoading(true);
      setLoadingMsg('Conectando à nuvem...');
      try {
        // 1. Tentar Supabase primeiro se houver config
        if (sbConfig.url && sbConfig.key) {
          const cloudData = await supabaseService.fetchClients(sbConfig);
          if (cloudData && cloudData.length > 0) {
            console.log(`Carregado ${cloudData.length} registros do Supabase.`);
            setClientData(cloudData);
            setDataSource('SUPABASE');
            // Cache local para offline
            await dbService.saveClients(cloudData);
            setIsLoading(false);
            return;
          }
        }

        // 2. Tentar Local DB (IndexedDB)
        const dbData = await dbService.getAllClients();
        if (dbData && dbData.length > 0) {
          setClientData(dbData);
          setDataSource('LOCAL_DB');
        } else {
          setClientData(MOCK_DATA);
          setDataSource('MOCK');
        }
      } catch (error) {
        console.error("Erro ao carregar dados:", error);
        setClientData(MOCK_DATA);
        setDataSource('MOCK');
      } finally {
        setIsLoading(false);
      }
    };
    loadData();
  }, [sbConfig]);

  useEffect(() => {
    localStorage.setItem(TAB_STORAGE_KEY, activeTab);
  }, [activeTab]);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const [modalOpen, setModalOpen] = useState(false);
  const [modalTitle, setModalTitle] = useState('');
  const [modalClients, setModalClients] = useState<ClientRecord[]>([]);

  const exportToCSV = (data: any[], filename: string) => {
    if (!data || !data.length) {
      alert("Sem dados para exportar.");
      return;
    }
    const headers = Object.keys(data[0]);
    const csvContent = [
      headers.join(';'),
      ...data.map(row => headers.map(fieldName => {
         let val = row[fieldName];
         if (val === null || val === undefined) val = '';
         val = String(val);
         if (val.includes('"') || val.includes(';')) val = `"${val.replace(/"/g, '""')}"`;
         return val;
      }).join(';'))
    ].join('\r\n');

    const blob = new Blob(['\uFEFF' + csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    const url = URL.createObjectURL(blob);
    link.setAttribute("href", url);
    link.setAttribute("download", `${filename}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleDownloadTemplate = () => {
    const headers = [
      "Código", "Razão Social / Nome", "Nome Fantasia", "CNPJ", "I. E.", 
      "Cidade", "UF", "Endereço (Logradouro)", "Número", "Bairro", "CEP", 
      "Ramo de atividade", "Grupo", "Ult. Compra", "Dias", "Cadastro", 
      "Representante Padrão", "Situação de bloqueio", "Situação do Cliente", 
      "Motivo de bloqueio", "pesquisa de ordem.Representante", "Representante Padrão - Copiar", 
      "Cidades", "Habitantes", "Rep", "rep2", "rep 3", "Supervisor"
    ];
    const exampleRow = ["4523", "EXEMPLO", "FANTASIA", "00.000.000/0001-00", "IE", "BAURU", "SP", "RUA", "10", "BAIRRO", "000", "RAMO", "", "01/01/2024", "10", "01/01/2020", "REP", "Normal", "Ativo", "", "REP", "REP", "BAURU-SP", "379297", "REP", "REP", "REP", "SUP"];
    const csvContent = [headers.join(';'), exampleRow.join(';')].join('\r\n');
    const blob = new Blob(['\uFEFF' + csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    link.setAttribute("href", URL.createObjectURL(blob));
    link.setAttribute("download", "modelo_importacao.csv");
    link.click();
  };

  const handleSaveConfig = () => {
    localStorage.setItem(SUPABASE_CONFIG_KEY, JSON.stringify(sbConfig));
    setShowConfigModal(false);
    window.location.reload(); // Recarrega para aplicar nova conexão
  };

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setIsLoading(true);
    setLoadingMsg('Importando e Sincronizando...');

    const reader = new FileReader();
    reader.onload = async (e) => {
      const text = e.target?.result as string;
      if (!text) { setIsLoading(false); return; }

      try {
        const lines = text.split(/\r?\n/).filter(line => line.trim() !== '');
        const delimiter = lines[0].includes(';') ? ';' : ',';
        const dataLines = lines.slice(1);

        const newRecords: ClientRecord[] = dataLines.map((line, index) => {
          const cols = line.split(delimiter);
          if (cols.length < 5) return null;
          const clean = (val: string) => val ? val.replace(/"/g, '').trim() : '';

          const statusRaw = clean(cols[18]);
          let status = ClientStatus.ACTIVE;
          if (statusRaw === 'Semi-ativo') status = ClientStatus.SEMI_ACTIVE;
          if (statusRaw === 'Inativo') status = ClientStatus.INACTIVE;

          const parseDate = (d: string) => {
            const parts = clean(d).split('/');
            return parts.length === 3 ? `${parts[2]}-${parts[1]}-${parts[0]}` : new Date().toISOString().split('T')[0];
          };

          const standardRep = clean(cols[24]) || clean(cols[20]) || 'Indefinido';

          return {
            id: clean(cols[0]) || `IMP-${index}`,
            socialName: clean(cols[1]),
            fantasyName: clean(cols[2]),
            cnpj: clean(cols[3]),
            ie: clean(cols[4]),
            city: clean(cols[5]),
            state: clean(cols[6]),
            address: `${clean(cols[7])}, ${clean(cols[8])}`,
            neighborhood: clean(cols[9]),
            cep: clean(cols[10]),
            activity: clean(cols[11]),
            group: clean(cols[12]),
            lastPurchaseDate: parseDate(cols[13]),
            daysSincePurchase: parseInt(clean(cols[14]).replace(/\D/g, '') || '0', 10),
            registerDate: parseDate(cols[15]),
            representativeName: standardRep,
            population: parseInt(clean(cols[23]).replace(/\D/g, '') || '0', 10),
            status: status,
            rep3: clean(cols[26]) || standardRep, 
            supervisor: clean(cols[27]) || 'GERAL'
          };
        }).filter(r => r !== null) as ClientRecord[];

        if (newRecords.length > 0) {
          // 1. Salvar Local
          await dbService.saveClients(newRecords);
          setClientData(newRecords);

          // 2. Sincronizar Supabase
          if (sbConfig.url && sbConfig.key) {
             setLoadingMsg('Subindo para o Supabase...');
             await supabaseService.saveClients(sbConfig, newRecords);
             setDataSource('SUPABASE');
             alert(`${newRecords.length} registros sincronizados na nuvem!`);
          } else {
             setDataSource('LOCAL_DB');
             alert(`${newRecords.length} registros salvos localmente (Nuvem não configurada).`);
          }
        }
      } catch (err: any) {
        console.error(err);
        alert('Erro ao processar: ' + err.message);
      } finally {
        setIsLoading(false);
      }
    };
    reader.readAsText(file);
  };

  const handleResetData = async () => {
    if (confirm("Deseja apagar os dados locais? (Dados na nuvem permanecerão no Supabase)")) {
      await dbService.clearDB();
      window.location.reload();
    }
  };

  const handleDrillDown = (filters: any) => {
    let filtered = clientData;
    if (filters.rep) filtered = filtered.filter(c => c.rep3 === filters.rep);
    if (filters.city) filtered = filtered.filter(c => c.city === filters.city);
    if (filters.supervisor) filtered = filtered.filter(c => c.supervisor === filters.supervisor);
    if (filters.status) {
      if (Array.isArray(filters.status)) filtered = filtered.filter(c => (filters.status as any).includes(c.status));
      else filtered = filtered.filter(c => c.status === filters.status);
    }
    setModalTitle(`Detalhes`);
    setModalClients(filtered);
    setModalOpen(true);
  };

  return (
    <div className="min-h-screen bg-gray-100 font-sans text-gray-800">

      {/* Top Status Bar */}
      <div className={`w-full py-1 text-center text-xs font-bold uppercase tracking-wider text-white flex justify-center items-center gap-4 ${dataSource === 'SUPABASE' ? 'bg-emerald-600' : (dataSource === 'LOCAL_DB' ? 'bg-blue-600' : 'bg-gray-500')}`}>
        <span>
          {dataSource === 'SUPABASE' 
            ? <><i className="fas fa-cloud mr-2"></i> Conectado ao Supabase</> 
            : dataSource === 'LOCAL_DB'
            ? <><i className="fas fa-database mr-2"></i> Armazenamento Local</>
            : <><i className="fas fa-info-circle mr-2"></i> Dados de Demonstração</>}
        </span>
      </div>

      {isLoading && (
        <div className="fixed inset-0 bg-black/50 z-[100] flex items-center justify-center backdrop-blur-sm">
           <div className="bg-white p-6 rounded-2xl shadow-2xl flex flex-col items-center">
             <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-900 mb-4"></div>
             <p className="text-blue-900 font-bold">{loadingMsg}</p>
           </div>
        </div>
      )}

      {/* Supabase Config Modal */}
      {showConfigModal && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[90] flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md overflow-hidden animate-fade-in">
            <div className="bg-emerald-800 text-white p-4 font-bold flex justify-between items-center">
              <span><i className="fas fa-bolt mr-2"></i> Configurar Supabase</span>
              <button onClick={() => setShowConfigModal(false)}><i className="fas fa-times"></i></button>
            </div>
            <div className="p-6 space-y-4">
              <div>
                <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Project URL</label>
                <input 
                  type="text" 
                  value={sbConfig.url} 
                  onChange={e => setSbConfig({...sbConfig, url: e.target.value})}
                  className="w-full border p-2 rounded" placeholder="https://xxxx.supabase.co"
                />
              </div>
              <div>
                <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Anon / Public API Key</label>
                <input 
                  type="password" 
                  value={sbConfig.key} 
                  onChange={e => setSbConfig({...sbConfig, key: e.target.value})}
                  className="w-full border p-2 rounded" placeholder="eyJhbGciOiJIUzI1NiIsInR5cCI..."
                />
              </div>
              <p className="text-[10px] text-gray-400">
                Certifique-se de que a tabela <b>clients</b> existe e tem políticas RLS para permitir inserção/leitura.
              </p>
              <button onClick={handleSaveConfig} className="w-full bg-emerald-600 text-white py-2 rounded font-bold hover:bg-emerald-700">
                Conectar e Salvar
              </button>
            </div>
          </div>
        </div>
      )}

      <div className="p-4 md:p-6">
        <div className="max-w-6xl mx-auto bg-white shadow-2xl rounded-3xl overflow-hidden border border-gray-100">

          <div className="bg-gradient-to-r from-blue-900 to-blue-800 text-white p-6 rounded-t-3xl">
            <div className="flex flex-col md:flex-row justify-between items-center gap-6">
              <div>
                <h1 className="text-3xl font-bold tracking-tight flex items-center gap-3">
                  <i className="fas fa-chart-pie"></i>
                  Millenium Dashboard
                </h1>
                <p className="text-blue-200 text-sm mt-1">Sincronização Cloud via Supabase</p>
              </div>

              <div className="flex flex-wrap justify-center gap-2 items-center">
                <button onClick={handleDownloadTemplate} className="bg-white/10 hover:bg-white/20 text-white px-3 py-2 rounded-lg text-xs font-semibold flex items-center gap-2 border border-white/20">
                  <i className="fas fa-download"></i> Modelo
                </button>

                <div className="relative">
                  <input type="file" accept=".csv" ref={fileInputRef} onChange={handleFileUpload} className="hidden" />
                  <button onClick={() => fileInputRef.current?.click()} className="bg-yellow-400 hover:bg-yellow-300 text-blue-900 px-4 py-2 rounded-lg text-sm font-bold flex items-center gap-2 shadow-lg">
                    <i className="fas fa-file-import"></i> Importar CSV
                  </button>
                </div>

                <div className="h-8 w-px bg-white/20 mx-1"></div>

                 <button 
                  onClick={() => setShowConfigModal(true)}
                  className={`w-9 h-9 rounded-lg flex items-center justify-center transition-all border ${dataSource === 'SUPABASE' ? 'bg-emerald-600 border-emerald-500' : 'bg-gray-700 border-gray-600'}`}
                  title="Configurar Supabase"
                >
                  <i className="fas fa-plug"></i>
                </button>

                <button onClick={handleResetData} className="bg-red-500/80 hover:bg-red-500 text-white px-3 py-2 rounded-lg text-xs font-bold shadow-sm" title="Limpar Local">
                  <i className="fas fa-eraser"></i>
                </button>
              </div>
            </div>
          </div>

          <div className="flex flex-wrap border-b border-gray-200 bg-gray-50/50 p-2 gap-2">
            {[
              { id: 'representative', icon: 'fa-user-tie', label: 'Representante' },
              { id: 'city', icon: 'fa-city', label: 'Cidade' },
              { id: 'supervisor', icon: 'fa-user-shield', label: 'Supervisor' }
            ].map((tab) => (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id as Tab)}
                className={`flex-1 py-3 px-4 rounded-xl text-center font-bold text-sm transition-all duration-200 ${
                  activeTab === tab.id
                    ? 'bg-white text-blue-900 shadow-md ring-1 ring-black/5'
                    : 'text-gray-500 hover:text-blue-700 hover:bg-gray-100'
                }`}
              >
                <i className={`fas ${tab.icon} mr-2`}></i> {tab.label}
              </button>
            ))}
          </div>

          <div className="p-6 md:p-8 bg-white min-h-[500px]">
            {activeTab === 'representative' ? (
              <RepresentativeTab data={clientData} onExport={exportToCSV} onDrillDown={handleDrillDown} />
            ) : activeTab === 'city' ? (
              <CityTab data={clientData} onExport={exportToCSV} onDrillDown={handleDrillDown} />
            ) : (
              <SupervisorTab data={clientData} onExport={exportToCSV} onDrillDown={handleDrillDown} />
            )}
          </div>
        </div>
        <ClientListModal isOpen={modalOpen} onClose={() => setModalOpen(false)} title={modalTitle} clients={modalClients} />
      </div>
    </div>
  );
};

