import React, { useState, useRef, useEffect } from 'react';
import RepresentativeTab from './components/RepresentativeTab';
import CityTab from './components/CityTab';
import SupervisorTab from './components/SupervisorTab';
import ClientListModal from './components/ClientListModal';
import { MOCK_DATA } from './services/mockData';
import { dbService } from './services/database'; 
import { supabaseService, SupabaseConfig } from './services/supabaseService';
import { ClientRecord, ClientStatus } from './types';

type Tab = 'representative' | 'city' | 'supervisor';
type DataSource = 'MOCK' | 'LOCAL_DB' | 'SUPABASE';

const TAB_STORAGE_KEY = 'MILLENIUM_PREF_ACTIVE_TAB';
const SUPABASE_CONFIG_KEY = 'MILLENIUM_SUPABASE_CONFIG';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<Tab>(() => {
    return (localStorage.getItem(TAB_STORAGE_KEY) as Tab) || 'representative';
  });

  const [isLoading, setIsLoading] = useState(true);
  const [loadingMsg, setLoadingMsg] = useState('Processando...');
  const [clientData, setClientData] = useState<ClientRecord[]>([]);
  const [dataSource, setDataSource] = useState<DataSource>('MOCK');

  const [showConfigModal, setShowConfigModal] = useState(false);
  const [sbConfig, setSbConfig] = useState<SupabaseConfig>(() => {
    const saved = localStorage.getItem(SUPABASE_CONFIG_KEY);
    return saved ? JSON.parse(saved) : { url: '', key: '' };
  });

  useEffect(() => {
    const loadData = async () => {
      setIsLoading(true);
      setLoadingMsg('Conectando à nuvem...');
      try {
        if (sbConfig.url && sbConfig.key) {
          const cloudData = await supabaseService.fetchClients(sbConfig);
          if (cloudData && cloudData.length > 0) {
            setClientData(cloudData);
            setDataSource('SUPABASE');
            await dbService.saveClients(cloudData);
            setIsLoading(false);
            return;
          }
        }

        const dbData = await dbService.getAllClients();
        if (dbData && dbData.length > 0) {
          setClientData(dbData);
          setDataSource('LOCAL_DB');
        } else {
          setClientData(MOCK_DATA);
          setDataSource('MOCK');
        }
      } catch (error) {
        setClientData(MOCK_DATA);
        setDataSource('MOCK');
      } finally {
        setIsLoading(false);
      }
    };
    loadData();
  }, [sbConfig]);

  useEffect(() => {
    localStorage.setItem(TAB_STORAGE_KEY, activeTab);
  }, [activeTab]);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const [modalOpen, setModalOpen] = useState(false);
  const [modalTitle, setModalTitle] = useState('');
  const [modalClients, setModalClients] = useState<ClientRecord[]>([]);

  const exportToCSV = (data: any[], filename: string) => {
    if (!data || !data.length) return;
    const headers = Object.keys(data[0]);
    const csvContent = [
      headers.join(';'),
      ...data.map(row => headers.map(fieldName => {
         let val = row[fieldName] ?? '';
         val = String(val);
         if (val.includes('"') || val.includes(';')) val = `"${val.replace(/"/g, '""')}"`;
         return val;
      }).join(';'))
    ].join('\r\n');

    const blob = new Blob(['\uFEFF' + csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    link.href = URL.createObjectURL(blob);
    link.download = `${filename}.csv`;
    link.click();
  };

  const parseCSVLine = (line: string, delimiter: string) => {
    const parts = [];
    let current = '';
    let inQuotes = false;
    for (let i = 0; i < line.length; i++) {
      const char = line[i];
      if (char === '"') {
        if (inQuotes && line[i + 1] === '"') {
          current += '"';
          i++;
        } else {
          inQuotes = !inQuotes;
        }
      } else if (char === delimiter && !inQuotes) {
        parts.push(current);
        current = '';
      } else {
        current += char;
      }
    }
    parts.push(current);
    return parts;
  };

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setIsLoading(true);
    setLoadingMsg('Importando e Sincronizando...');

    const reader = new FileReader();
    reader.onload = async (e) => {
      const text = e.target?.result as string;
      if (!text) { setIsLoading(false); return; }

      try {
        const lines = text.split(/\r?\n/).filter(line => line.trim() !== '');
        if (lines.length < 2) { setIsLoading(false); return; }

        const firstLine = lines[0];
        const counts = { ';': (firstLine.match(/;/g) || []).length, ',': (firstLine.match(/,/g) || []).length, '\t': (firstLine.match(/\t/g) || []).length };
        const delimiter = (Object.keys(counts) as Array<keyof typeof counts>).reduce((a, b) => counts[a] > counts[b] ? a : b);

        const newRecords: ClientRecord[] = lines.slice(1).map((line, index) => {
          const cols = parseCSVLine(line, delimiter);
          if (cols.length < 5) return null;

          const clean = (val: string) => val ? val.trim().replace(/^"|"$/g, '') : '';

          const parseDate = (d: string) => {
            if (!d) return new Date().toISOString().split('T')[0];
            const dateOnly = clean(d).split(' ')[0];
            const parts = dateOnly.split('/');
            if (parts.length === 3) {
                const day = parts[0].padStart(2, '0');
                const month = parts[1].padStart(2, '0');
                const year = parts[2].length === 2 ? `20${parts[2]}` : parts[2];
                return `${year}-${month}-${day}`;
            }
            return new Date().toISOString().split('T')[0];
          };

          const statusRaw = clean(cols[18]);
          let status = ClientStatus.ACTIVE;
          if (statusRaw.toLowerCase().includes('semi')) status = ClientStatus.SEMI_ACTIVE;
          else if (statusRaw.toLowerCase().includes('inativo')) status = ClientStatus.INACTIVE;

          const standardRep = clean(cols[24]) || clean(cols[16]) || 'Indefinido';

          return {
            id: clean(cols[0]) || `IMP-${7000 + index}`,
            socialName: clean(cols[1]),
            fantasyName: clean(cols[2]),
            cnpj: clean(cols[3]),
            ie: clean(cols[4]),
            city: clean(cols[5]),
            state: clean(cols[6]),
            address: clean(cols[8]) ? `${clean(cols[7])}, ${clean(cols[8])}` : clean(cols[7]),
            neighborhood: clean(cols[9]),
            cep: clean(cols[10]),
            activity: clean(cols[11]),
            group: clean(cols[12]),
            lastPurchaseDate: parseDate(cols[13]),
            daysSincePurchase: parseInt(clean(cols[14]).replace(/\D/g, '') || '0', 10),
            registerDate: parseDate(cols[15]),
            representativeName: standardRep,
            population: parseInt(clean(cols[23]).replace(/\D/g, '') || '0', 10),
            status: status,
            rep3: clean(cols[26]) || standardRep, 
            supervisor: clean(cols[27]) || 'GERAL'
          };
        }).filter(r => r !== null) as ClientRecord[];

        if (newRecords.length > 0) {
          await dbService.saveClients(newRecords);
          setClientData(newRecords);
          if (sbConfig.url && sbConfig.key) {
             setLoadingMsg('Sincronizando na Nuvem...');
             await supabaseService.saveClients(sbConfig, newRecords);
             setDataSource('SUPABASE');
          } else {
             setDataSource('LOCAL_DB');
          }
          alert(`${newRecords.length} clientes importados com sucesso.`);
        }
      } catch (err: any) {
        alert('Erro na importação: ' + err.message);
      } finally {
        setIsLoading(false);
      }
    };
    reader.readAsText(file);
  };

  const handleResetData = async () => {
    if (confirm("Apagar dados locais?")) {
      await dbService.clearDB();
      window.location.reload();
    }
  };

  const handleDrillDown = (filters: any) => {
    let filtered = clientData;
    if (filters.rep) filtered = filtered.filter(c => c.rep3 === filters.rep);
    if (filters.city) filtered = filtered.filter(c => c.city === filters.city);
    if (filters.supervisor) filtered = filtered.filter(c => c.supervisor === filters.supervisor);
    if (filters.status) {
      if (Array.isArray(filters.status)) filtered = filtered.filter(c => (filters.status as any).includes(c.status));
      else filtered = filtered.filter(c => c.status === filters.status);
    }
    setModalTitle(`Filtro Ativo`);
    setModalClients(filtered);
    setModalOpen(true);
  };

  return (
    <div className="min-h-screen bg-gray-100 font-sans text-gray-800">
      <div className={`w-full py-1 text-center text-xs font-bold uppercase tracking-wider text-white flex justify-center items-center gap-4 ${dataSource === 'SUPABASE' ? 'bg-emerald-600' : (dataSource === 'LOCAL_DB' ? 'bg-blue-600' : 'bg-gray-500')}`}>
        <span>
          {dataSource === 'SUPABASE' ? <><i className="fas fa-cloud mr-2"></i> Cloud Ativa</> : <><i className="fas fa-database mr-2"></i> Local Ativo</>}
        </span>
      </div>

      {isLoading && (
        <div className="fixed inset-0 bg-black/50 z-[100] flex items-center justify-center backdrop-blur-sm">
           <div className="bg-white p-6 rounded-2xl shadow-2xl flex flex-col items-center">
             <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-900 mb-4"></div>
             <p className="text-blue-900 font-bold">{loadingMsg}</p>
           </div>
        </div>
      )}

      {showConfigModal && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[90] flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md overflow-hidden animate-fade-in">
            <div className="bg-emerald-800 text-white p-4 font-bold flex justify-between items-center">
              <span><i className="fas fa-bolt mr-2"></i> Supabase</span>
              <button onClick={() => setShowConfigModal(false)}><i className="fas fa-times"></i></button>
            </div>
            <div className="p-6 space-y-4">
              <input type="text" value={sbConfig.url} onChange={e => setSbConfig({...sbConfig, url: e.target.value})} className="w-full border p-2 rounded" placeholder="Project URL" />
              <input type="password" value={sbConfig.key} onChange={e => setSbConfig({...sbConfig, key: e.target.value})} className="w-full border p-2 rounded" placeholder="API Key" />
              <button onClick={() => { localStorage.setItem(SUPABASE_CONFIG_KEY, JSON.stringify(sbConfig)); setShowConfigModal(false); window.location.reload(); }} className="w-full bg-emerald-600 text-white py-2 rounded font-bold">Salvar</button>
            </div>
          </div>
        </div>
      )}

      <div className="p-4 md:p-6">
        <div className="max-w-6xl mx-auto bg-white shadow-2xl rounded-3xl overflow-hidden border border-gray-100">
          <div className="bg-gradient-to-r from-blue-900 to-blue-800 text-white p-6 rounded-t-3xl">
            <div className="flex flex-col md:flex-row justify-between items-center gap-6">
              <div>
                <h1 className="text-3xl font-bold flex items-center gap-3"><i className="fas fa-chart-pie"></i> Millenium</h1>
              </div>
              <div className="flex flex-wrap justify-center gap-2 items-center">
                <input type="file" accept=".csv" ref={fileInputRef} onChange={handleFileUpload} className="hidden" />
                <button onClick={() => fileInputRef.current?.click()} className="bg-yellow-400 hover:bg-yellow-300 text-blue-900 px-4 py-2 rounded-lg text-sm font-bold flex items-center gap-2 shadow-lg">
                  <i className="fas fa-file-import"></i> Importar CSV
                </button>
                <button onClick={() => setShowConfigModal(true)} className="w-9 h-9 rounded-lg bg-gray-700 flex items-center justify-center transition-all border border-gray-600"><i className="fas fa-plug text-white"></i></button>
                <button onClick={handleResetData} className="bg-red-500/80 hover:bg-red-500 text-white px-3 py-2 rounded-lg text-xs font-bold"><i className="fas fa-eraser"></i></button>
              </div>
            </div>
          </div>

          <div className="flex flex-wrap border-b border-gray-200 bg-gray-50/50 p-2 gap-2">
            {['representative', 'city', 'supervisor'].map((tab) => (
              <button key={tab} onClick={() => setActiveTab(tab as Tab)} className={`flex-1 py-3 px-4 rounded-xl text-center font-bold text-sm transition-all ${activeTab === tab ? 'bg-white text-blue-900 shadow-md ring-1 ring-black/5' : 'text-gray-500 hover:text-blue-700'}`}>
                {tab.charAt(0).toUpperCase() + tab.slice(1)}
              </button>
            ))}
          </div>

          <div className="p-6 md:p-8 bg-white min-h-[500px]">
            {activeTab === 'representative' ? <RepresentativeTab data={clientData} onExport={exportToCSV} onDrillDown={handleDrillDown} /> : activeTab === 'city' ? <CityTab data={clientData} onExport={exportToCSV} onDrillDown={handleDrillDown} /> : <SupervisorTab data={clientData} onExport={exportToCSV} onDrillDown={handleDrillDown} />}
          </div>
        </div>
        <ClientListModal isOpen={modalOpen} onClose={() => setModalOpen(false)} title={modalTitle} clients={modalClients} />
      </div>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import RepresentativeTab from './components/RepresentativeTab';
import CityTab from './components/CityTab';
import SupervisorTab from './components/SupervisorTab';
import ClientListModal from './components/ClientListModal';
import { MOCK_DATA } from './services/mockData';
import { dbService } from './services/database'; 
import { supabaseService, SupabaseConfig } from './services/supabaseService';
import { ClientRecord, ClientStatus } from './types';

type Tab = 'representative' | 'city' | 'supervisor';
type DataSource = 'MOCK' | 'LOCAL_DB' | 'SUPABASE';

const TAB_STORAGE_KEY = 'MILLENIUM_PREF_ACTIVE_TAB';
const SUPABASE_CONFIG_KEY = 'MILLENIUM_SUPABASE_CONFIG';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<Tab>(() => {
    return (localStorage.getItem(TAB_STORAGE_KEY) as Tab) || 'representative';
  });

  const [isLoading, setIsLoading] = useState(true);
  const [loadingMsg, setLoadingMsg] = useState('Processando...');
  const [clientData, setClientData] = useState<ClientRecord[]>([]);
  const [dataSource, setDataSource] = useState<DataSource>('MOCK');

  const [showConfigModal, setShowConfigModal] = useState(false);
  const [sbConfig, setSbConfig] = useState<SupabaseConfig>(() => {
    const saved = localStorage.getItem(SUPABASE_CONFIG_KEY);
    return saved ? JSON.parse(saved) : { url: '', key: '' };
  });

  useEffect(() => {
    const loadData = async () => {
      setIsLoading(true);
      setLoadingMsg('Conectando à nuvem...');
      try {
        if (sbConfig.url && sbConfig.key) {
          const cloudData = await supabaseService.fetchClients(sbConfig);
          if (cloudData && cloudData.length > 0) {
            setClientData(cloudData);
            setDataSource('SUPABASE');
            await dbService.saveClients(cloudData);
            setIsLoading(false);
            return;
          }
        }

        const dbData = await dbService.getAllClients();
        if (dbData && dbData.length > 0) {
          setClientData(dbData);
          setDataSource('LOCAL_DB');
        } else {
          setClientData(MOCK_DATA);
          setDataSource('MOCK');
        }
      } catch (error) {
        setClientData(MOCK_DATA);
        setDataSource('MOCK');
      } finally {
        setIsLoading(false);
      }
    };
    loadData();
  }, [sbConfig]);

  useEffect(() => {
    localStorage.setItem(TAB_STORAGE_KEY, activeTab);
  }, [activeTab]);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const [modalOpen, setModalOpen] = useState(false);
  const [modalTitle, setModalTitle] = useState('');
  const [modalClients, setModalClients] = useState<ClientRecord[]>([]);

  const exportToCSV = (data: any[], filename: string) => {
    if (!data || !data.length) return;
    const headers = Object.keys(data[0]);
    const csvContent = [
      headers.join(';'),
      ...data.map(row => headers.map(fieldName => {
         let val = row[fieldName] ?? '';
         val = String(val);
         if (val.includes('"') || val.includes(';')) val = `"${val.replace(/"/g, '""')}"`;
         return val;
      }).join(';'))
    ].join('\r\n');

    const blob = new Blob(['\uFEFF' + csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    link.href = URL.createObjectURL(blob);
    link.download = `${filename}.csv`;
    link.click();
  };

  const parseCSVLine = (line: string, delimiter: string) => {
    const parts = [];
    let current = '';
    let inQuotes = false;
    for (let i = 0; i < line.length; i++) {
      const char = line[i];
      if (char === '"') {
        if (inQuotes && line[i + 1] === '"') {
          current += '"';
          i++;
        } else {
          inQuotes = !inQuotes;
        }
      } else if (char === delimiter && !inQuotes) {
        parts.push(current);
        current = '';
      } else {
        current += char;
      }
    }
    parts.push(current);
    return parts;
  };

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setIsLoading(true);
    setLoadingMsg('Importando e Sincronizando...');

    const reader = new FileReader();
    reader.onload = async (e) => {
      const text = e.target?.result as string;
      if (!text) { setIsLoading(false); return; }

      try {
        const lines = text.split(/\r?\n/).filter(line => line.trim() !== '');
        if (lines.length < 2) { setIsLoading(false); return; }

        // Detectar delimitador de forma mais robusta analisando várias linhas
        const sampleLines = lines.slice(0, 5).join('\n');
        const counts = { ';': (sampleLines.match(/;/g) || []).length, ',': (sampleLines.match(/,/g) || []).length, '\t': (sampleLines.match(/\t/g) || []).length };
        const delimiter = (Object.keys(counts) as Array<keyof typeof counts>).reduce((a, b) => counts[a] > counts[b] ? a : b);

        // Encontrar a linha do cabeçalho (que contém Código ou Razão Social)
        let headerIndex = -1;
        let colMap: Record<string, number> = {};

        for (let i = 0; i < Math.min(lines.length, 10); i++) {
          const cols = parseCSVLine(lines[i], delimiter).map(c => c.trim().toLowerCase());
          if (cols.includes('código') || cols.includes('codigo') || cols.includes('razão social') || cols.includes('razao social')) {
            headerIndex = i;
            cols.forEach((name, idx) => {
              if (name) colMap[name] = idx;
            });
            break;
          }
        }

        // Se não achou cabeçalho nomeado, usa o mapeamento padrão do Millenium
        if (headerIndex === -1) {
          headerIndex = 0; // Tenta começar da primeira linha se falhar a detecção
        }

        const getCol = (cols: string[], possibleNames: string[], defaultIdx: number) => {
          for (const name of possibleNames) {
            if (colMap[name.toLowerCase()] !== undefined) return cols[colMap[name.toLowerCase()]];
          }
          return cols[defaultIdx];
        };

        const newRecords: ClientRecord[] = lines.slice(headerIndex + 1).map((line, index) => {
          const cols = parseCSVLine(line, delimiter);
          if (cols.length < 5) return null;

          const clean = (val: string) => val ? val.trim().replace(/^"|"$/g, '') : '';

          // Verificar se a primeira coluna é realmente um código (numérico ou preenchido)
          // Se col[0] for vazio e não achamos código em outro lugar, pode ser linha de lixo
          const rawId = getCol(cols, ['código', 'codigo'], 0);
          if (!rawId || rawId.toLowerCase().includes('positivação') || rawId.toLowerCase().includes('total')) return null;

          const parseDate = (d: string) => {
            if (!d) return new Date().toISOString().split('T')[0];
            const dateOnly = clean(d).split(' ')[0]; // Remove horário se houver (Ex: 15/12/2025 00:00)
            const parts = dateOnly.split('/');
            if (parts.length === 3) {
                const day = parts[0].padStart(2, '0');
                const month = parts[1].padStart(2, '0');
                const year = parts[2].length === 2 ? `20${parts[2]}` : parts[2];
                return `${year}-${month}-${day}`;
            }
            return new Date().toISOString().split('T')[0];
          };

          const statusRaw = getCol(cols, ['situação do cliente', 'situacao do cliente', 'status'], 18) || '';
          let status = ClientStatus.ACTIVE;
          if (statusRaw.toLowerCase().includes('semi')) status = ClientStatus.SEMI_ACTIVE;
          else if (statusRaw.toLowerCase().includes('inativo')) status = ClientStatus.INACTIVE;

          const standardRep = getCol(cols, ['representante padrão - copiar', 'representante', 'rep'], 24) || 
                              getCol(cols, ['representante padrão'], 16) || 'Indefinido';

          return {
            id: clean(rawId),
            socialName: clean(getCol(cols, ['razão social / nome', 'razao social / nome', 'razão social', 'razao social'], 1)),
            fantasyName: clean(getCol(cols, ['nome fantasia', 'fantasia'], 2)),
            cnpj: clean(getCol(cols, ['cnpj'], 3)),
            ie: clean(getCol(cols, ['i. e.', 'ie'], 4)),
            city: clean(getCol(cols, ['cidade'], 5)),
            state: clean(getCol(cols, ['uf'], 6)),
            address: clean(getCol(cols, ['número', 'numero'], 8)) 
                     ? `${clean(getCol(cols, ['endereço (logradouro)', 'endereco', 'logradouro'], 7))}, ${clean(getCol(cols, ['número', 'numero'], 8))}` 
                     : clean(getCol(cols, ['endereço (logradouro)', 'endereco', 'logradouro'], 7)),
            neighborhood: clean(getCol(cols, ['bairro'], 9)),
            cep: clean(getCol(cols, ['cep'], 10)),
            activity: clean(getCol(cols, ['ramo de atividade', 'ramo'], 11)),
            group: clean(getCol(cols, ['grupo'], 12)),
            lastPurchaseDate: parseDate(getCol(cols, ['ult. compra', 'ultima compra'], 13)),
            daysSincePurchase: parseInt(clean(getCol(cols, ['dias'], 14)).replace(/\D/g, '') || '0', 10),
            registerDate: parseDate(getCol(cols, ['cadastro'], 15)),
            representativeName: clean(standardRep),
            population: parseInt(clean(getCol(cols, ['habitantes'], 23)).replace(/\D/g, '') || '0', 10),
            status: status,
            rep3: clean(getCol(cols, ['rep 3', 'rep3'], 26)) || clean(standardRep), 
            supervisor: clean(getCol(cols, ['supervisor'], 27)) || 'GERAL'
          };
        }).filter(r => r !== null) as ClientRecord[];

        if (newRecords.length > 0) {
          await dbService.saveClients(newRecords);
          setClientData(newRecords);
          if (sbConfig.url && sbConfig.key) {
             setLoadingMsg('Sincronizando na Nuvem...');
             await supabaseService.saveClients(sbConfig, newRecords);
             setDataSource('SUPABASE');
          } else {
             setDataSource('LOCAL_DB');
          }
          alert(`${newRecords.length} clientes importados com sucesso.`);
        } else {
          alert('Nenhum dado válido encontrado no arquivo. Verifique se o formato está correto.');
        }
      } catch (err: any) {
        alert('Erro na importação: ' + err.message);
      } finally {
        setIsLoading(false);
        if (event.target) event.target.value = '';
      }
    };
    reader.readAsText(file);
  };

  const handleResetData = async () => {
    if (confirm("Apagar dados locais?")) {
      await dbService.clearDB();
      window.location.reload();
    }
  };

  const handleDrillDown = (filters: any) => {
    let filtered = clientData;
    if (filters.rep) filtered = filtered.filter(c => c.rep3 === filters.rep);
    if (filters.city) filtered = filtered.filter(c => c.city === filters.city);
    if (filters.supervisor) filtered = filtered.filter(c => c.supervisor === filters.supervisor);
    if (filters.status) {
      if (Array.isArray(filters.status)) filtered = filtered.filter(c => (filters.status as any).includes(c.status));
      else filtered = filtered.filter(c => c.status === filters.status);
    }
    setModalTitle(`Filtro Ativo`);
    setModalClients(filtered);
    setModalOpen(true);
  };

  return (
    <div className="min-h-screen bg-gray-100 font-sans text-gray-800">
      <div className={`w-full py-1 text-center text-xs font-bold uppercase tracking-wider text-white flex justify-center items-center gap-4 ${dataSource === 'SUPABASE' ? 'bg-emerald-600' : (dataSource === 'LOCAL_DB' ? 'bg-blue-600' : 'bg-gray-500')}`}>
        <span>
          {dataSource === 'SUPABASE' ? <><i className="fas fa-cloud mr-2"></i> Cloud Ativa</> : <><i className="fas fa-database mr-2"></i> Local Ativo</>}
