import React, { useState, useRef, useEffect } from 'react';
import RepresentativeTab from './components/RepresentativeTab';
import CityTab from './components/CityTab';
import SupervisorTab from './components/SupervisorTab';
import ClientListModal from './components/ClientListModal';
import { MOCK_DATA } from './services/mockData';
import { dbService } from './services/database'; 
import { supabaseService, SupabaseConfig } from './services/supabaseService';
import { ClientRecord, ClientStatus } from './types';

type Tab = 'representative' | 'city' | 'supervisor';
type DataSource = 'MOCK' | 'LOCAL_DB' | 'SUPABASE';

const TAB_STORAGE_KEY = 'MILLENIUM_PREF_ACTIVE_TAB';
const SUPABASE_CONFIG_KEY = 'MILLENIUM_SUPABASE_CONFIG';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<Tab>(() => {
    return (localStorage.getItem(TAB_STORAGE_KEY) as Tab) || 'representative';
  });

  const [isLoading, setIsLoading] = useState(true);
  const [loadingMsg, setLoadingMsg] = useState('Processando...');
  const [clientData, setClientData] = useState<ClientRecord[]>([]);
  const [dataSource, setDataSource] = useState<DataSource>('MOCK');

  const [showConfigModal, setShowConfigModal] = useState(false);
  const [sbConfig, setSbConfig] = useState<SupabaseConfig>(() => {
    const saved = localStorage.getItem(SUPABASE_CONFIG_KEY);
    return saved ? JSON.parse(saved) : { url: '', key: '' };
  });

  useEffect(() => {
    const loadData = async () => {
      setIsLoading(true);
      setLoadingMsg('Carregando banco de dados...');
      try {
        if (sbConfig.url && sbConfig.key) {
          const cloudData = await supabaseService.fetchClients(sbConfig);
          if (cloudData && cloudData.length > 0) {
            setClientData(cloudData);
            setDataSource('SUPABASE');
            await dbService.saveClients(cloudData);
            setIsLoading(false);
            return;
          }
        }

        const dbData = await dbService.getAllClients();
        if (dbData && dbData.length > 0) {
          setClientData(dbData);
          setDataSource('LOCAL_DB');
        } else {
          setClientData(MOCK_DATA);
          setDataSource('MOCK');
        }
      } catch (error) {
        setClientData(MOCK_DATA);
        setDataSource('MOCK');
      } finally {
        setIsLoading(false);
      }
    };
    loadData();
  }, [sbConfig]);

  useEffect(() => {
    localStorage.setItem(TAB_STORAGE_KEY, activeTab);
  }, [activeTab]);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const [modalOpen, setModalOpen] = useState(false);
  const [modalTitle, setModalTitle] = useState('');
  const [modalClients, setModalClients] = useState<ClientRecord[]>([]);

  // Robust CSV Parser that handles quotes and delimiters inside values
  const parseCSVLine = (line: string, delimiter: string) => {
    const parts = [];
    let current = '';
    let inQuotes = false;
    for (let i = 0; i < line.length; i++) {
      const char = line[i];
      if (char === '"') {
        if (inQuotes && line[i + 1] === '"') {
          current += '"';
          i++;
        } else {
          inQuotes = !inQuotes;
        }
      } else if (char === delimiter && !inQuotes) {
        parts.push(current);
        current = '';
      } else {
        current += char;
      }
    }
    parts.push(current);
    return parts;
  };

  const handleDownloadTemplate = () => {
    const headers = [
      "Código", "Razão Social / Nome", "Nome Fantasia", "CNPJ", "I. E.", 
      "Cidade", "UF", "Endereço (Logradouro)", "Número", "Bairro", "CEP", 
      "Ramo de atividade", "Grupo", "Ult. Compra", "Dias", "Cadastro", 
      "Representante Padrão", "Situação do Cliente", "rep 3", "Supervisor", "Habitantes"
    ];
    const exampleRow = ["215746", "L.F.B PROD [BRILHANTE]", "BRILHANTE", "58.531.529/0001-11", "194.279.910.119", "AVARE", "SP", "R DONA CARMEM DIAS FARIA", "2969", "ALTO", "18708-030", "LOJA", "GERAL", "15/12/2025", "51", "01/01/2024", "RAFAELA REIS", "Ativo", "RAFAELA REIS", "BARONI", "91232"];
    const csvContent = [headers.join(';'), exampleRow.join(';')].join('\r\n');
    const blob = new Blob(['\uFEFF' + csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    link.href = URL.createObjectURL(blob);
    link.download = "modelo_millenium.csv";
    link.click();
  };

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setIsLoading(true);
    setLoadingMsg('Processando relatório...');

    const reader = new FileReader();
    reader.onload = async (e) => {
      const text = e.target?.result as string;
      if (!text) { setIsLoading(false); return; }

      try {
        const lines = text.split(/\r?\n/).filter(line => line.trim() !== '');

        // Dynamic Delimiter Detection
        const sample = lines.slice(0, 10).join('\n');
        const counts = { ';': (sample.match(/;/g) || []).length, ',': (sample.match(/,/g) || []).length };
        const delimiter = counts[';'] >= counts[','] ? ';' : ',';

        // 1. Find Header Row Dinamically
        let headerIndex = -1;
        let colMap: Record<string, number> = {};

        for (let i = 0; i < Math.min(lines.length, 30); i++) {
          const cols = parseCSVLine(lines[i], delimiter).map(c => c.trim().toLowerCase());
          if (cols.some(c => c.includes('código') || c.includes('codigo') || c.includes('razão') || c.includes('razao'))) {
            headerIndex = i;
            cols.forEach((name, idx) => {
              if (name) colMap[name] = idx;
            });
            break;
          }
        }

        if (headerIndex === -1) {
          throw new Error("Não foi possível localizar o cabeçalho das colunas (Código, Razão Social, etc).");
        }

        const getVal = (cols: string[], aliases: string[]) => {
          for (const alias of aliases) {
            const idx = colMap[alias.toLowerCase()];
            if (idx !== undefined && cols[idx] !== undefined) {
              return cols[idx].trim().replace(/^"|"$/g, '').trim();
            }
          }
          return '';
        };

        // 2. Map Data Lines
        const newRecords: ClientRecord[] = lines.slice(headerIndex + 1).map((line) => {
          const cols = parseCSVLine(line, delimiter);

          const rawId = getVal(cols, ['código', 'codigo', 'id', 'cod']);
          // Skip empty lines or summary lines
          if (!rawId || rawId.toLowerCase().includes('total') || rawId.toLowerCase() === 'código') return null;

          const rawStatus = getVal(cols, ['situação do cliente', 'situacao do cliente', 'situação', 'status', 'situacao']);
          let status = ClientStatus.ACTIVE;
          if (rawStatus.toLowerCase().includes('semi')) status = ClientStatus.SEMI_ACTIVE;
          else if (rawStatus.toLowerCase().includes('inativo')) status = ClientStatus.INACTIVE;

          const standardRep = getVal(cols, ['rep 3', 'rep3', 'representante padrão - copiar', 'representante padrão', 'representante', 'rep', 'vendedor']) || 'Indefinido';

          const parseDate = (d: string) => {
            if (!d) return new Date().toISOString().split('T')[0];
            const cleanD = d.trim().split(' ')[0];
            const parts = cleanD.split('/');
            if (parts.length === 3) {
                const day = parts[0].padStart(2, '0');
                const month = parts[1].padStart(2, '0');
                const year = parts[2].length === 2 ? `20${parts[2]}` : parts[2];
                return `${year}-${month}-${day}`;
            }
            return new Date().toISOString().split('T')[0];
          };

          const logradouro = getVal(cols, ['endereço (logradouro)', 'endereco', 'logradouro', 'rua']);
          const numero = getVal(cols, ['número', 'numero', 'nº']);

          return {
            id: rawId,
            socialName: getVal(cols, ['razão social / nome', 'razao social / nome', 'razão social', 'razao social', 'nome']),
            fantasyName: getVal(cols, ['nome fantasia', 'fantasia']),
            cnpj: getVal(cols, ['cnpj']),
            ie: getVal(cols, ['i. e.', 'ie']),
            city: getVal(cols, ['cidade']),
            state: getVal(cols, ['uf', 'estado']),
            address: numero ? `${logradouro}, ${numero}` : logradouro,
            neighborhood: getVal(cols, ['bairro']),
            cep: getVal(cols, ['cep']),
            activity: getVal(cols, ['ramo de atividade', 'ramo', 'atividade']),
            group: getVal(cols, ['grupo']),
            lastPurchaseDate: parseDate(getVal(cols, ['ult. compra', 'ultima compra', 'dt ult. compra'])),
            daysSincePurchase: parseInt(getVal(cols, ['dias']).replace(/\D/g, '') || '0', 10),
            registerDate: parseDate(getVal(cols, ['cadastro', 'dt. cadastro'])),
            representativeName: standardRep,
            rep3: getVal(cols, ['rep 3', 'rep3']) || standardRep,
            supervisor: getVal(cols, ['supervisor', 'setor', 'gerente']) || 'GERAL',
            population: parseInt(getVal(cols, ['habitantes', 'populacao']).replace(/\D/g, '') || '0', 10),
            status: status
          };
        }).filter(r => r !== null) as ClientRecord[];

        if (newRecords.length > 0) {
          await dbService.saveClients(newRecords);
          setClientData(newRecords);
          if (sbConfig.url && sbConfig.key) {
             setLoadingMsg('Sincronizando nuvem...');
             await supabaseService.saveClients(sbConfig, newRecords);
             setDataSource('SUPABASE');
          } else {
             setDataSource('LOCAL_DB');
          }
          alert(`${newRecords.length} clientes integrados com sucesso!`);
        } else {
          alert('Nenhum dado válido encontrado. Verifique se o cabeçalho "Código" está presente.');
        }
      } catch (err: any) {
        alert('Erro na importação: ' + err.message);
      } finally {
        setIsLoading(false);
        if (event.target) event.target.value = '';
      }
    };
    reader.readAsText(file);
  };

  const handleResetData = async () => {
    if (confirm("Apagar todos os dados locais?")) {
      await dbService.clearDB();
      window.location.reload();
    }
  };

  const handleDrillDown = (filters: any) => {
    let filtered = clientData;
    if (filters.rep) filtered = filtered.filter(c => c.rep3 === filters.rep);
    if (filters.city) filtered = filtered.filter(c => c.city === filters.city);
    if (filters.supervisor) filtered = filtered.filter(c => c.supervisor === filters.supervisor);
    if (filters.status) {
      if (Array.isArray(filters.status)) filtered = filtered.filter(c => (filters.status as any).includes(c.status));
      else filtered = filtered.filter(c => c.status === filters.status);
    }
    setModalTitle(`Detalhamento`);
    setModalClients(filtered);
    setModalOpen(true);
  };

  const exportToCSV = (data: any[], filename: string) => {
    if (!data || !data.length) return;
    const headers = Object.keys(data[0]);
    const csvContent = [
      headers.join(';'),
      ...data.map(row => headers.map(fieldName => {
         let val = row[fieldName] ?? '';
         val = String(val);
         if (val.includes('"') || val.includes(';')) val = `"${val.replace(/"/g, '""')}"`;
         return val;
      }).join(';'))
    ].join('\r\n');

    const blob = new Blob(['\uFEFF' + csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    link.href = URL.createObjectURL(blob);
    link.download = `${filename}.csv`;
    link.click();
  };

  return (
    <div className="min-h-screen bg-gray-100 font-sans text-gray-800">
      <div className={`w-full py-1 text-center text-[10px] font-bold uppercase tracking-widest text-white flex justify-center items-center gap-4 ${dataSource === 'SUPABASE' ? 'bg-emerald-600' : (dataSource === 'LOCAL_DB' ? 'bg-blue-600' : 'bg-gray-500')}`}>
        <span>
          <i className={`fas ${dataSource === 'SUPABASE' ? 'fa-cloud' : 'fa-database'} mr-2`}></i>
          {dataSource === 'SUPABASE' ? 'Sync Nuvem Ativo' : 'Base Local Ativa'}
        </span>
      </div>

      {isLoading && (
        <div className="fixed inset-0 bg-black/50 z-[100] flex items-center justify-center backdrop-blur-sm">
           <div className="bg-white p-6 rounded-2xl shadow-2xl flex flex-col items-center">
             <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-900 mb-4"></div>
             <p className="text-blue-900 font-bold">{loadingMsg}</p>
           </div>
        </div>
      )}

      {showConfigModal && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[90] flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md overflow-hidden">
            <div className="bg-emerald-800 text-white p-4 font-bold flex justify-between items-center">
              <span>Configurar Supabase</span>
              <button onClick={() => setShowConfigModal(false)}><i className="fas fa-times"></i></button>
            </div>
            <div className="p-6 space-y-4">
              <input type="text" value={sbConfig.url} onChange={e => setSbConfig({...sbConfig, url: e.target.value})} className="w-full border p-2 rounded" placeholder="Project URL" />
              <input type="password" value={sbConfig.key} onChange={e => setSbConfig({...sbConfig, key: e.target.value})} className="w-full border p-2 rounded" placeholder="Anon Key" />
              <button onClick={() => { localStorage.setItem(SUPABASE_CONFIG_KEY, JSON.stringify(sbConfig)); setShowConfigModal(false); window.location.reload(); }} className="w-full bg-emerald-600 text-white py-2 rounded font-bold">Salvar e Conectar</button>
            </div>
          </div>
        </div>
      )}

      <div className="p-4 md:p-6">
        <div className="max-w-6xl mx-auto bg-white shadow-2xl rounded-3xl overflow-hidden">
          <div className="bg-gradient-to-r from-blue-900 to-blue-800 text-white p-6">
            <div className="flex flex-col md:flex-row justify-between items-center gap-6">
              <h1 className="text-3xl font-bold flex items-center gap-3">
                <i className="fas fa-chart-line text-yellow-400"></i> Millenium
              </h1>
              <div className="flex flex-wrap justify-center gap-3 items-center">
                <button onClick={handleDownloadTemplate} className="bg-white/10 hover:bg-white/20 text-white px-3 py-2 rounded-lg text-xs font-bold border border-white/20">
                   Modelo CSV
                </button>
                <input type="file" accept=".csv" ref={fileInputRef} onChange={handleFileUpload} className="hidden" />
                <button onClick={() => fileInputRef.current?.click()} className="bg-yellow-400 hover:bg-yellow-300 text-blue-900 px-5 py-2 rounded-lg text-sm font-bold flex items-center shadow-lg transform active:scale-95 transition-all">
                  <i className="fas fa-file-import mr-2"></i> Importar CSV
                </button>
                <button onClick={() => setShowConfigModal(true)} className="w-10 h-10 rounded-lg bg-gray-700 flex items-center justify-center border border-gray-600 hover:bg-gray-600"><i className="fas fa-plug text-white"></i></button>
                <button onClick={handleResetData} className="w-10 h-10 rounded-lg bg-red-600 flex items-center justify-center border border-red-500 hover:bg-red-500"><i className="fas fa-trash text-white"></i></button>
              </div>
            </div>
          </div>

          <div className="flex border-b border-gray-200 bg-gray-50/50 p-2 gap-2">
            {['representative', 'city', 'supervisor'].map((tab) => (
              <button key={tab} onClick={() => setActiveTab(tab as Tab)} className={`flex-1 py-3 rounded-xl font-bold text-sm transition-all ${activeTab === tab ? 'bg-white text-blue-900 shadow-md ring-1 ring-black/5' : 'text-gray-500 hover:text-blue-700'}`}>
                {tab === 'representative' ? 'Por Representante' : tab === 'city' ? 'Por Cidade' : 'Por Supervisor'}
              </button>
            ))}
          </div>

          <div className="p-6 md:p-8 min-h-[500px] bg-white">
            {activeTab === 'representative' ? <RepresentativeTab data={clientData} onExport={exportToCSV} onDrillDown={handleDrillDown} /> : activeTab === 'city' ? <CityTab data={clientData} onExport={exportToCSV} onDrillDown={handleDrillDown} /> : <SupervisorTab data={clientData} onExport={exportToCSV} onDrillDown={handleDrillDown} />}
          </div>
        </div>
      </div>
      <ClientListModal isOpen={modalOpen} onClose={() => setModalOpen(false)} title={modalTitle} clients={modalClients} />
    </div>
  );
};

